    double calculateFare(double distance, int minutes);
    String getName();
}

class PoolFare implements FareStrategy {
    public double calculateFare(double distance, int minutes) { return 0.5 * distance + 0.1 * minutes; }
    public String getName() { return "Pool"; }
}

class RegularFare implements FareStrategy {
    public double calculateFare(double distance, int minutes) { return 1.0 * distance + 0.2 * minutes; }
    public String getName() { return "Regular"; }
}

class PremiumFare implements FareStrategy {
    public double calculateFare(double distance, int minutes) { return 2.0 * distance + 0.5 * minutes + 5.0; }
    public String getName() { return "Premium"; }
}

class SurgeFare implements FareStrategy {
    private FareStrategy baseFare;
    private double multiplier;
    public SurgeFare(FareStrategy base, double mult) { this.baseFare = base; this.multiplier = mult; }
    public double calculateFare(double distance, int minutes) { return baseFare.calculateFare(distance, minutes) * multiplier; }
    public String getName() { return baseFare.getName() + " (" + multiplier + "x surge)"; }
}

