    public static FareStrategy create(String type, double surge) {
        FareStrategy fare;
        if (type.equals("POOL")) fare = new PoolFare();
        else if (type.equals("PREMIUM")) fare = new PremiumFare();
        else fare = new RegularFare();
        return surge > 1.0 ? new SurgeFare(fare, surge) : fare;
    }
}

public class Main {
    public static void main(String[] args) {
        FareStrategy fare;

        fare = FareFactory.create("POOL", 1.0);
        System.out.println("Pool: $" + fare.calculateFare(10, 20) + " (" + fare.getName() + ")");

        fare = FareFactory.create("PREMIUM", 1.0);
